            aOrbiterJ = ((aWandererE + RotL64(aIngress, 5U)) + RotL64(aCarry, 5U)) + 0x346249023B78ECAFULL;
            aOrbiterE = (aWandererB + RotL64(aScatter, 34U)) + 0xA4B9D884FD81EEFDULL;
            //
            aOrbiterH = (aOrbiterH + aOrbiterA) + 0x2258D1116AD4ADFAULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterH) ^ 0x97BA70A147B11CD4ULL;
            aOrbiterB = RotL64((aOrbiterB * 0x9C45D1BE9550A3F9ULL), 27U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterH) + 0xEF7D0659E61D57D2ULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterI) ^ 0x87BD103B5BCC2733ULL;
            aOrbiterC = RotL64((aOrbiterC * 0xE891254B6BFB0D87ULL), 37U);
