            aOrbiterH = RotL64((aOrbiterH * 0xA56C128ECEE118DFULL), 23U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterH) + 0x38DB7E732E904D96ULL) + aPhaseBOrbiterUpdateSaltF[(((31U - aIndex) + 7U)) & S_SALT1];
