            aOrbiterA = (aWandererD + RotL64(aIngress, 11U)) + 0x3DA72B7E761E4B52ULL;
            aOrbiterB = (aWandererC + RotL64(aPrevious, 27U)) + 0x9E9B14B71B3440DCULL;
